from elasticsearch import Elasticsearch
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Initialize Elasticsearch client
es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

def index_document(index_name, document):
    try:
        response = es.index(index=index_name, body=document)
        logger.info(f"Indexed document with ID: {response['_id']}")
    except Exception as e:
        logger.error(f"Failed to index document: {e}")

def search_documents(index_name, query):
    try:
        response = es.search(index=index_name, body={"query": {"match": {"content": query}}})
        return response['hits']['hits']
    except Exception as e:
        logger.error(f"Search failed: {e}")
        return []

def log_aggregation(index_name, field):
    try:
        response = es.search(
            index=index_name,
            body={
                "size": 0,
                "aggs": {
                    "log_counts": {
                        "terms": {"field": field}
                    }
                }
            }
        )
        return response['aggregations']['log_counts']['buckets']
    except Exception as e:
        logger.error(f"Aggregation failed: {e}")
        return []

